// Extract the PDF download URL from Amazon Kindle email
const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.html || item.json.textHtml || '';
  const text = item.json.text || item.json.textPlain || '';
  const subject = item.json.subject || '';

  let downloadUrl = '';

  // Strategy 1: Look for Amazon download links in href attributes
  const hrefRegex = /href=["']([^"']*amazon[^"']*(?:download|file|attachment)[^"']*)["']/gi;
  const allHrefs = [...html.matchAll(hrefRegex)];
  if (allHrefs.length > 0) {
    downloadUrl = allHrefs[0][1];
  }

  // Strategy 2: Look for any download/file-download links
  if (!downloadUrl) {
    const dlRegex = /href=["'](https?:\/\/[^"']*(?:download|file-download|attachment)[^"']*)["']/gi;
    const dlMatch = dlRegex.exec(html);
    if (dlMatch) downloadUrl = dlMatch[1];
  }

  // Strategy 3: Look for Amazon URLs with "download" or "file" in plain text
  if (!downloadUrl) {
    const textUrlRegex = /(https?:\/\/[^\s]*amazon[^\s]*(?:download|file)[^\s]*)/gi;
    const textMatch = textUrlRegex.exec(text);
    if (textMatch) downloadUrl = textMatch[1];
  }

  // Strategy 4: Look for any link that ends in .pdf
  if (!downloadUrl) {
    const pdfRegex = /href=["'](https?:\/\/[^"']*\.pdf[^"']*)["']/gi;
    const pdfMatch = pdfRegex.exec(html);
    if (pdfMatch) downloadUrl = pdfMatch[1];
  }

  // Strategy 5: Look for "Download PDF" button link text
  if (!downloadUrl) {
    const btnRegex = /href=["'](https?:\/\/[^"']+)["'][^>]*>(?:[^<]*(?:Download|View)[^<]*PDF[^<]*)<\/a>/gi;
    const btnMatch = btnRegex.exec(html);
    if (btnMatch) downloadUrl = btnMatch[1];
  }

  // Extract notebook name from subject line
  let notebookName = 'Kindle_Note';
  const nameMatch = subject.match(/sent a file ["\u201c]([^"\u201d]+)["\u201d]/i);
  if (nameMatch) {
    notebookName = nameMatch[1].replace(/[^a-zA-Z0-9\s-]/g, '').replace(/\s+/g, '_');
  }

  if (!downloadUrl) {
    throw new Error('Could not find PDF download URL in email. Subject: ' + subject + '. HTML length: ' + html.length);
  }

  // Decode HTML entities in the URL
  downloadUrl = downloadUrl.replace(/&amp;/g, '&');

  results.push({
    json: {
      downloadUrl: downloadUrl,
      notebookName: notebookName,
      emailSubject: subject,
      emailDate: item.json.date || new Date().toISOString(),
      fileName: notebookName + '.pdf'
    }
  });
}

return results;
